func carre(_ n: Int) -> Int {
    return n * n
}

func parite(_ n: Int) -> String {
    if n % 2 == 0 {
        return "pair"
    } else {
        return "impair"
    }
}

func action(_ feu: String) -> String {
    switch feu {
    case "rouge": return "stop"
    case "orange": return "ralentir"
    case "vert": return "go"
    default: return "inconnu"
    }
}

func accueil(_ prenom: String?) -> String {
    if let prenom = prenom {
        return "Salut \(prenom)"
    } else {
        return "Salut inconnu"
    }
}

struct Personne {
    let nom: String
    func bonjour() -> String {
        return "Bonjour \(nom)"
    }
}

func oppose(_ d: Direction) -> Direction {
    switch d {
    case .nord: return .sud
    case .sud: return .nord
    case .est: return .ouest
    case .ouest: return .est
    }
}
